import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import Footer from '../components/Footer';
import API from '../api/axios';
import './Swimwear.css';

const FILTERS = [
  { label: 'All',       value: 'all' },
  { label: 'Bikinis',   value: 'bikinis' },
  { label: 'Sets',      value: 'sets' },
  { label: 'One-Piece', value: 'one-piece' },
  { label: 'Dresses',   value: 'dresses' },
];

export default function Swimwear() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [active, setActive]     = useState('all');
  const navigate = useNavigate();

  useEffect(() => {
    API.get('/products/?category__slug=swimwear&ordering=-created_at&page_size=50')
      .then(({ data }) => setProducts(data.results || data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const filtered = active === 'all'
    ? products
    : products.filter(p => p.subcategory?.slug === active || p.tags?.includes(active));

  return (
    <>
      <Header />
      <main>

        {/* ── Hero ── */}
        <section className="sw-hero">
          <div
            className="sw-hero__bg"
            style={{ backgroundImage: "url('/boit1.jpeg')", backgroundPosition: 'center 30%' }}
          />
          <div className="sw-hero__overlay" />
          <div className="sw-hero__content">
            <p className="sw-hero__eyebrow">SS 2025 — Dreaminlace</p>
            <h1 className="sw-hero__title">Swim<br /><em>wear</em></h1>
            <div className="sw-hero__meta">
              <span>New collection</span>
              <span>{products.length} styles</span>
              <span>XS – XXXL</span>
            </div>
          </div>
        </section>

        {/* ── Filter bar ── */}
        <div className="sw-filters">
          <div className="sw-filters__cats">
            {FILTERS.map(f => (
              <button
                key={f.value}
                className={`sw-filter-btn${active === f.value ? ' active' : ''}`}
                onClick={() => setActive(f.value)}
              >
                {f.label}
              </button>
            ))}
          </div>
          <span className="sw-filters__count">{filtered.length} items</span>
        </div>

        {/* ── Product Grid ── */}
        {loading ? (
          <div className="spinner-wrap" style={{ minHeight: '40vh' }}>
            <div className="spinner" />
          </div>
        ) : (
          <div className="sw-grid">
            {filtered.map((p, i) => {
              // Support both {image_url} array and flat {thumbnail} from Django
              const mainImg  = p.images?.[0]?.image_url || p.thumbnail || p.image || '';
              const hoverImg = p.images?.[1]?.image_url || '';

              return (
                <React.Fragment key={p.id}>

                  {/* Editorial break after 6 products */}
                  {i === 6 && active === 'all' && (
                    <div className="sw-editorial" style={{ gridColumn: '1 / -1' }}>
                      {[
                        { src: '/image4.jpeg',  cap: 'The Collection', pos: 'center 30%' },
                        { src: '/boit4.jpeg',   cap: 'Sunset Edit',    pos: 'center 25%' },
                        { src: '/image59.jpeg', cap: 'Resort Wear',    pos: 'center 15%' },
                      ].map(({ src, cap, pos }) => (
                        <div className="sw-editorial__panel" key={cap}>
                          <div
                            className="sw-editorial__bg"
                            style={{ backgroundImage: `url('${src}')`, backgroundPosition: pos }}
                          />
                          <span className="sw-editorial__label">{cap}</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Product card — click navigates to /swimwear/:slug */}
                  <div
                    className="sw-card"
                    onClick={() => navigate(`/swimwear/${p.slug}`)}
                    role="button"
                    tabIndex={0}
                    onKeyDown={e => e.key === 'Enter' && navigate(`/swimwear/${p.slug}`)}
                  >
                    <div className="sw-card__gallery">
                      {mainImg && (
                        <img
                          className="sw-card__img sw-card__img--main"
                          src={mainImg}
                          alt={p.name}
                          loading={i < 8 ? 'eager' : 'lazy'}
                        />
                      )}
                      {hoverImg && (
                        <img
                          className="sw-card__img sw-card__img--hover"
                          src={hoverImg}
                          alt={`${p.name} alternate view`}
                          loading="lazy"
                        />
                      )}
                      {p.is_new && (
                        <span className="sw-card__badge sw-card__badge--new">New</span>
                      )}
                      {p.is_featured && !p.is_new && (
                        <span className="sw-card__badge sw-card__badge--hot">Hot</span>
                      )}
                      {p.images?.length > 1 && (
                        <span className="sw-card__img-count">{p.images.length} photos</span>
                      )}
                      <div className="sw-card__actions">
                        <button
                          className="sw-card__action-btn"
                          onClick={e => { e.stopPropagation(); navigate(`/swimwear/${p.slug}`); }}
                          aria-label="View product"
                        >
                          <svg viewBox="0 0 24 24" strokeWidth="1.3">
                            <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
                            <circle cx="12" cy="12" r="3"/>
                          </svg>
                        </button>
                        <button
                          className="sw-card__action-btn"
                          onClick={e => e.stopPropagation()}
                          aria-label="Add to wishlist"
                        >
                          <svg viewBox="0 0 24 24" strokeWidth="1.3">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
                          </svg>
                        </button>
                      </div>
                    </div>
                    <div className="sw-card__info">
                      <p className="sw-card__name">{p.name}</p>
                      <p className="sw-card__price">R {parseFloat(p.price).toLocaleString()}</p>
                    </div>
                  </div>
                </React.Fragment>
              );
            })}
          </div>
        )}

        {/* ── Size guidance strip ── */}
        <div className="sw-size-strip">
          <div className="sw-size-strip__text">
            <h3>Not sure of your size?</h3>
            <p>Our pieces are designed to move with you. We stock XS through XXXL in every style.</p>
          </div>
          <Link to="/size-guide" className="btn-ghost">View Size Guide</Link>
        </div>

      </main>
      <Footer />
    </>
  );
}
